+      signalCode: null,
+      killed: false,
+    }));
+
+    const runner = new ExecutableRunner(target, { projectRoot, logger: makeLogger() });
+    await runner.onBuildSuccess();
+    await runner.stop();
+
+    expect(killMock).toHaveBeenCalledWith('SIGTERM');
+  });
+});

